using Autodesk.AutoCAD.ApplicationServices;using Autodesk.AutoCAD.DatabaseServices;using Autodesk.AutoCAD.EditorInput;using Autodesk.AutoCAD.Geometry;using Autodesk.AutoCAD.Runtime;
namespace Tgirrr.CadLisp { public sealed class CopySequenceCommands { [CommandMethod("CPLUS")] public void CPlus(){var doc=Application.DocumentManager.MdiActiveDocument;var ed=doc.Editor;var opt=new PromptEntityOptions("\nChọn TEXT hoặc MTEXT có nội dung cần tăng: ");opt.SetRejectMessage("\nChỉ hỗ trợ TEXT và MTEXT.");opt.AddAllowedClass(typeof(DBText),false);opt.AddAllowedClass(typeof(MText),false);var pick=ed.GetEntity(opt);if(pick.Status!=PromptStatus.OK)return;string original;Point3d insertion;using(var tr=doc.TransactionManager.StartTransaction()){var entity=(Entity)tr.GetObject(pick.ObjectId,OpenMode.ForRead);original=entity is DBText t?t.TextString:((MText)entity).Contents;insertion=entity is DBText dt?dt.Position:((MText)entity).Location;}var window=new CopySequenceWindow(original);if(Application.ShowModalWindow(window)!=true)return;var baseResult=ed.GetPoint("\nChọn điểm gốc copy: ");if(baseResult.Status!=PromptStatus.OK)return;int index=1,count=0;using(doc.LockDocument()){while(true){var point=ed.GetPoint(new PromptPointOptions("\nChọn điểm đặt bản copy <Enter để kết thúc>: "){BasePoint=baseResult.Value,UseBasePoint=true,UseDashedLine=true});if(point.Status!=PromptStatus.OK)break;var next=CopySequenceService.Apply(original,window.Settings,index);if(next==null){ed.WriteMessage("\nDanh sách đã hết.");break;}using(var tr=doc.TransactionManager.StartTransaction()){var source=(Entity)tr.GetObject(pick.ObjectId,OpenMode.ForRead);var clone=(Entity)source.Clone();clone.TransformBy(Matrix3d.Displacement(point.Value-baseResult.Value));if(clone is DBText text)text.TextString=next;else((MText)clone).Contents=next;var space=(BlockTableRecord)tr.GetObject(doc.Database.CurrentSpaceId,OpenMode.ForWrite);space.AppendEntity(clone);tr.AddNewlyCreatedDBObject(clone,true);tr.Commit();}index++;count++;}}ed.WriteMessage("\nCPLUS: Đã tạo "+count+" bản copy.");}}
}
